// Pico Traffic Light
// Red → Red+Yellow → Green → Yellow → repeat

#include <Arduino.h>

const int RED_PIN    = 13;  // GP13
const int YELLOW_PIN = 14;  // GP14
const int GREEN_PIN  = 15;  // GP15

void allOff() {
  digitalWrite(RED_PIN, LOW);
  digitalWrite(YELLOW_PIN, LOW);
  digitalWrite(GREEN_PIN, LOW);
}

void setup() {
  pinMode(RED_PIN, OUTPUT);
  pinMode(YELLOW_PIN, OUTPUT);
  pinMode(GREEN_PIN, OUTPUT);
  Serial.begin(115200);
  delay(100);
  Serial.println("Pico Traffic Light started");
}

void loop() {
  // RED
  allOff();
  digitalWrite(RED_PIN, HIGH);
  Serial.println("RED - STOP");
  delay(3000);

  // RED + YELLOW (get ready)
  digitalWrite(YELLOW_PIN, HIGH);
  Serial.println("RED+YELLOW - GET READY");
  delay(1000);

  // GREEN
  allOff();
  digitalWrite(GREEN_PIN, HIGH);
  Serial.println("GREEN - GO");
  delay(3000);

  // YELLOW (caution)
  allOff();
  digitalWrite(YELLOW_PIN, HIGH);
  Serial.println("YELLOW - CAUTION");
  delay(1500);
}
